window.SD_WL=(function(){var _w={};var _ok=false;try{var _r=localStorage.getItem('sd_wl_v1');if(_r){_w=JSON.parse(_r)||{};_ok=!!_w.site_name;}}catch(e){}var n=_w.site_name||'';return{brand_name:n,brand_tagline:_w.site_slogan||'',contact_email:_w.email||'',instagram:_w.instagram||'',facebook:_w.facebook||'',pinterest:_w.pinterest||'',free_shipping_threshold:_w.free_shipping_threshold||50,announcement:{sv:_w.announcement_sv||'Fri frakt från 50€ · Säker betalning',fr:_w.announcement_fr||'Livraison gratuite dès 50€ · Produits nordiques & britanniques · Paiement sécurisé',en:_w.announcement_en||'Free delivery from €50 · Nordic & British products · Secure payment'},footer_desc:{sv:_w.footer_desc_sv||'',fr:_w.footer_desc_fr||'',en:_w.footer_desc_en||''},footer_tagline:{sv:_w.footer_tagline_sv||'',fr:_w.footer_tagline_fr||'',en:_w.footer_tagline_en||''},copyright:{sv:'© 2026 '+n+' · Alla rättigheter förbehållna',fr:'© 2026 '+n+' · Tous droits réservés',en:'© 2026 '+n+' · All rights reserved'},_ready:_ok};})();
let cart=JSON.parse(localStorage.getItem('sd_cart')||'{}');
let LANG=localStorage.getItem('sd_lang')||'sv';
function saveCart(){localStorage.setItem('sd_cart',JSON.stringify(cart));}
function saveLang(l){localStorage.setItem('sd_lang',l);}
function addToCart(id,qty=1,variant=null){const key=variant?`${id}_${variant}`:`${id}`;cart[key]=(cart[key]||0)+qty;saveCart();updateCartBadge();renderCartDrawer();const p=PRODUCTS.find(x=>x.id===id||x.uuid===id||String(x.id)===String(id));if(!p)return;try{const cp=JSON.parse(localStorage.getItem('sd_cart_products')||'{}');cp[String(id)]={name:p.name,photo:p.photo,price:p.price,weight:p.weight,variants:p.variants||[]};localStorage.setItem('sd_cart_products',JSON.stringify(cp));}catch(e){}_snipAdd(p,id,qty,variant);const name=p.name[LANG];showToast(name.substring(0,28)+(name.length>28?'…':'')+' — '+UI[LANG].addedCart);openCart();}
function openSnipcartCheckout(){closeCart();const here=window.location.pathname;if(!here.endsWith('panier.html')){window.location.href='panier.html';return;}const go=()=>{let co=document.getElementById('_snip-co');if(!co){co=document.createElement('button');co.id='_snip-co';co.className='snipcart-checkout';co.style.display='none';document.body.appendChild(co);}co.click();};if(typeof Snipcart!=='undefined'){go();}else{document.addEventListener('snipcart.ready',go,{once:true});if(window.LoadSnipcart)window.LoadSnipcart();}}
function _snipAdd(p,id,qty,variant){const doAdd=()=>{try{const sv=variant?p.variants?.find(v=>v.label===variant):p.variants?.[0];const price=(sv?sv.price:p.price)||0;const pid=variant?`${id}_${variant}`:String(id);const vp=variant?`?variant=${encodeURIComponent(variant)}`:'';const btn=document.createElement('button');btn.className='snipcart-add-item';btn.setAttribute('data-item-id',pid);btn.setAttribute('data-item-price',price.toFixed(2));btn.setAttribute('data-item-url',`${window.SD_API_URL||'https://svenska-backend.vercel.app'}/api/snipcart/${id}${vp}`);btn.setAttribute('data-item-name',(p.name?.fr||'')+(variant?' — '+variant:''));btn.setAttribute('data-item-image',p.photo||'');btn.setAttribute('data-item-quantity',String(qty));btn.style.cssText='position:fixed;top:-999px;left:-999px;width:1px;height:1px;';document.body.appendChild(btn);btn.click();setTimeout(()=>{try{btn.remove();}catch(e){}},1000);}catch(e){console.warn('[Snipcart add]',e);}};if(typeof Snipcart!=='undefined'){doAdd();}else{document.addEventListener('snipcart.ready',doAdd,{once:true});if(window.LoadSnipcart)window.LoadSnipcart();}}
function changeQty(key,delta){cart[key]=(cart[key]||0)+delta;const newQty=cart[key]||0;if(newQty<=0)delete cart[key];saveCart();updateCartBadge();renderCartDrawer();try{if(typeof Snipcart!=='undefined'&&Snipcart.api){if(newQty>0){Snipcart.api.cart.items.update({id:key,quantity:newQty}).catch(()=>{});}else{const items=Snipcart.store.getState().cart?.items?.items||[];const item=items.find(i=>i.id===key);if(item)Snipcart.api.cart.items.remove({uniqueId:item.uniqueId}).catch(()=>{});}}}catch(e){}}
function removeItem(key){delete cart[key];saveCart();updateCartBadge();renderCartDrawer();try{if(typeof Snipcart!=='undefined'&&Snipcart.api){const items=Snipcart.store.getState().cart?.items?.items||[];const item=items.find(i=>i.id===key);if(item)Snipcart.api.cart.items.remove({uniqueId:item.uniqueId}).catch(()=>{});}}catch(e){}}
function updateCartBadge(){const total=Object.values(cart).reduce((a,b)=>a+b,0);document.querySelectorAll('.cart-badge').forEach(el=>el.textContent=total);}
function cartTotal(){return Object.entries(cart).filter(([,q])=>q>0).reduce((sum,[key,qty])=>{const _ti=key.indexOf('_');const idStr=_ti===-1?key:key.slice(0,_ti);const variant=_ti===-1?undefined:key.slice(_ti+1);const _cpt=JSON.parse(localStorage.getItem('sd_cart_products')||'{}');const p=PRODUCTS.find(x=>String(x.uuid||x.id)===idStr||x.id===parseInt(idStr))||_cpt[idStr];if(!p)return sum;const v=variant?p.variants?.find(x=>x.label===variant):p.variants?.[0];return sum+(v?v.price:p.price)*qty;},0);}

function renderCartDrawer(){const list=document.getElementById('drawer-items-list');const foot=document.getElementById('drawer-footer');if(!list)return;const entries=Object.entries(cart).filter(([,q])=>q>0);if(entries.length===0){list.innerHTML=`<div class="cart-empty-msg">${UI[LANG].emptyCart}</div>`;if(foot)foot.style.display='none';return;}if(foot)foot.style.display='block';let total=0;list.innerHTML=entries.map(([key,qty])=>{const _ri=key.indexOf('_');const idStr=_ri===-1?key:key.slice(0,_ri);const variant=_ri===-1?undefined:key.slice(_ri+1);const _cpd=JSON.parse(localStorage.getItem('sd_cart_products')||'{}');const p=PRODUCTS.find(x=>String(x.uuid||x.id)===idStr||x.id===parseInt(idStr))||_cpd[idStr];if(!p)return'';const v=variant?p.variants?.find(x=>x.label===variant):p.variants?.[0];const price=v?v.price:p.price;const line=price*qty;total+=line;return`<div class="cart-row"><div class="cart-row-thumb" style="background-image:url('${p.photo}')"></div><div class="cart-row-info"><div class="cart-row-name">${p.name[LANG]}</div><div class="cart-row-sub">${variant||p.weight}</div><div class="cart-qty"><button class="cq-btn" onclick="changeQty('${key}',-1)">−</button><span class="cq-num">${qty}</span><button class="cq-btn" onclick="changeQty('${key}',1)">+</button></div></div><div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px;flex-shrink:0;"><span class="cart-row-price">€${line.toFixed(2)}</span><button class="cart-del" onclick="removeItem('${key}')">✕</button></div></div>`;}).join('');const totalEl=document.getElementById('cart-total-price');if(totalEl)totalEl.textContent='€'+total.toFixed(2);const shipEl=document.getElementById('cart-ship-note');if(shipEl){const remaining=50-total;if(remaining>0){const pct=Math.min(100,(total/50)*100);shipEl.innerHTML=`<div class="ship-bar"><div class="ship-bar-fill" style="width:${pct}%"></div></div><span>${LANG==='fr'?`Plus que €${remaining.toFixed(2)} pour la livraison gratuite`:LANG==='en'?`€${remaining.toFixed(2)} away from free delivery`:`€${remaining.toFixed(2)} kvar till fri frakt`}</span>`;}else{shipEl.innerHTML=`<span style="color:var(--moss);font-weight:600;">${UI[LANG].freeShip} ✓</span>`;}}}

function openCart(){document.getElementById('cart-drawer')?.classList.add('open');document.getElementById('drawer-overlay')?.classList.add('open');document.body.style.overflow='hidden';}
function closeCart(){document.getElementById('cart-drawer')?.classList.remove('open');document.getElementById('drawer-overlay')?.classList.remove('open');document.body.style.overflow='';}
function setLang(l){LANG=l;saveLang(l);document.documentElement.lang=l;document.querySelectorAll('[data-sv]').forEach(el=>{const v=el.getAttribute('data-'+l);if(v!==null)el.innerHTML=v;});document.querySelectorAll('[data-sv-ph]').forEach(el=>{const v=el.getAttribute('data-'+l+'-ph');if(v)el.placeholder=v;});document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.dataset.lang===l));renderCartDrawer();if(typeof onLangChange==='function')onLangChange(l);}
function openSearch(){document.getElementById('search-overlay')?.classList.add('open');setTimeout(()=>document.getElementById('search-inp')?.focus(),80);}
function closeSearch(){document.getElementById('search-overlay')?.classList.remove('open');const i=document.getElementById('search-inp');if(i)i.value='';document.getElementById('search-res').innerHTML='';}
function handleSearchClick(e){if(e.target===document.getElementById('search-overlay'))closeSearch();}
function doSearch(q){const res=document.getElementById('search-res');if(!res)return;if(!q.trim()){res.innerHTML='';return;}const ql=q.toLowerCase();const found=PRODUCTS.filter(p=>{const name=p.name||{};return(name.fr||'').toLowerCase().includes(ql)||(name.sv||'').toLowerCase().includes(ql)||(name.en||'').toLowerCase().includes(ql)||p.cat.toLowerCase().includes(ql)||(p.tags||[]).some(t=>t.toLowerCase().includes(ql));}).slice(0,6);if(!found.length){res.innerHTML=`<div style="padding:20px;text-align:center;font-family:var(--font-body);font-style:italic;color:var(--dust);">${UI[LANG].noResults} "${q}"</div>`;return;}res.innerHTML=found.map(p=>`<div class="search-item" onclick="closeSearch();window.location.href='produit.html?id=${p.uuid||p.id}'"><div class="search-thumb" style="background-image:url('${p.photo}')"></div><div><div class="search-item-name">${p.name[LANG]||p.name.fr||''}</div><div class="search-item-cat">${CAT_LABELS[p.cat]?.[LANG]||p.cat}</div></div><span class="search-item-price">€${(p.price||0).toFixed(2)}</span></div>`).join('');}
function showToast(msg){const t=document.getElementById('toast');if(!t)return;t.textContent=msg;t.classList.add('show');clearTimeout(window._tt);window._tt=setTimeout(()=>t.classList.remove('show'),2800);}
function openMob(){document.getElementById('mobile-nav')?.classList.add('open');document.body.style.overflow='hidden';}
function closeMob(){document.getElementById('mobile-nav')?.classList.remove('open');document.body.style.overflow='';}

function productCardHTML(p){const badge=p.badge?`<div class="prod-badge ${p.badge}">${getBadgeLabel(p.badge)}</div>`:'';const rating=parseFloat(p.rating)||4.5;const origin=typeof p.origin==='object'?p.origin[LANG]||'':p.origin||'';const navId=p.uuid||p.id;const addId=typeof p.id==='string'?`'${p.id}'`:p.id;const reviewLabel=LANG==='sv'?'omdömen':LANG==='en'?'reviews':'avis';return`<div class="prod-card" onclick="window.location.href='produit.html?id=${navId}'"><div class="prod-img">${badge}<div class="prod-img-inner"><img src="${p.photo||''}" alt="${p.name?.['fr']||''}" loading="lazy" onerror="this.style.display='none'" style="width:100%;height:100%;object-fit:contain;padding:8px;background:var(--cream);"></div><button class="prod-quick" onclick="event.stopPropagation();addToCart(${addId})" title="Ajouter"><svg width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="currentColor" stroke-width="1.8"><line x1="7" y1="1" x2="7" y2="13"/><line x1="1" y1="7" x2="13" y2="7"/></svg></button><button class="prod-wish" onclick="event.stopPropagation();this.classList.toggle('liked')"><svg width="14" height="13" viewBox="0 0 14 13" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M7 11.5C7 11.5 1 7.8 1 4a3 3 0 0 1 6 0 3 3 0 0 1 6 0c0 3.8-6 7.5-6 7.5z"/></svg></button></div><div class="prod-body"><div class="prod-cat">${CAT_LABELS[p.cat]?.[LANG]||p.cat||''}</div><div class="prod-rating"><span class="prod-rating-score">${rating}</span><span class="prod-rating-sep">·</span><span class="prod-rating-count">${p.reviews||0} ${reviewLabel}</span></div><div class="prod-name">${p.name?.[LANG]||''}</div><div class="prod-origin">${origin}</div><div class="prod-footer"><span class="prod-price">€${(p.price||0).toFixed(2)}</span><span class="prod-weight">${p.weight||''}</span></div></div></div>`;}
function getBadgeLabel(b){const m={'badge-new':{sv:'Ny',fr:'Nouveau',en:'New'},'badge-pop':{sv:'Bästsäljare',fr:'Best-seller',en:'Best-seller'},'badge-org':{sv:'Ekologisk',fr:'Bio',en:'Organic'},'badge-must':{sv:'Klassiker',fr:'Incontournable',en:'Must have'}};return m[b]?.[LANG]||'';}

